"use client";

import { useState, useEffect } from "react";
import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { getMyLoyaltyApi } from "@/lib/api/loyalty";
import { getImageUrl } from "@/lib/utils";

type NavLink = {
  href: string;
  label: string;
  section?: string;
};

const Navbar = () => {
  const pathname = usePathname();
  const { isAuthenticated, user, logout } = useAuth();
  const [activeSection, setActiveSection] = useState("home");
  const [isScrolled, setIsScrolled] = useState(false);
  const [lastScrollY, setLastScrollY] = useState(0);
  const [showNavbar, setShowNavbar] = useState(true);
  const [loyaltyPoints, setLoyaltyPoints] = useState<number | null>(null);

  // Only track sections on homepage
  const isHomePage = pathname === "/";
  const isAuthSection = pathname.startsWith("/auth");

  useEffect(() => {
    if (!isHomePage) return;

    const handleScroll = () => {
      const scrollPosition = window.scrollY;
      setIsScrolled(scrollPosition > 50);

      // Show navbar when scrolling up, hide when scrolling down
      if (scrollPosition < lastScrollY || scrollPosition < 100) {
        setShowNavbar(true);
      } else if (scrollPosition > lastScrollY && scrollPosition > 100) {
        setShowNavbar(false);
      }
      setLastScrollY(scrollPosition);

      // Define sections with their IDs
      const sections = [
        { id: "home", offset: 0 },
        { id: "features", offset: 0 },
        { id: "movies", offset: 0 },
        { id: "categories", offset: 0 },
        { id: "cta", offset: 0 },
      ];

      // Calculate offsets
      sections.forEach((section) => {
        const element = document.getElementById(section.id);
        if (element) {
          section.offset = element.offsetTop - 100; // 100px offset for navbar
        }
      });

      // Find active section
      let current = "home";
      for (let i = sections.length - 1; i >= 0; i--) {
        if (scrollPosition >= sections[i].offset) {
          current = sections[i].id;
          break;
        }
      }

      setActiveSection(current);
    };

    window.addEventListener("scroll", handleScroll);
    handleScroll(); // Initial check

    return () => window.removeEventListener("scroll", handleScroll);
  }, [isHomePage]);

  const homeNavLinks: NavLink[] = [
    { href: "/", label: "Home", section: "home" },
    { href: "/#features", label: "Features", section: "features" },
    { href: "/#movies", label: "Movies", section: "movies" },
    { href: "/#categories", label: "Categories", section: "categories" },
  ];

  const dashboardNavLinks: NavLink[] = [
    { href: "/", label: "Home" },
    { href: "/auth/movies", label: "Movies" },
    { href: "/auth/loyalty-points", label: "Loyalty points" },
    { href: "/auth/sales", label: "Sales" },
  ];

  const navLinks: NavLink[] = isAuthSection ? dashboardNavLinks : homeNavLinks;

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    if (href.startsWith("/#")) {
      e.preventDefault();
      const sectionId = href.substring(2);
      const element = document.getElementById(sectionId);
      if (element) {
        element.scrollIntoView({ behavior: "smooth", block: "start" });
      }
    }
  };

  useEffect(() => {
    if (!isAuthenticated) {
      setLoyaltyPoints(null);
      return;
    }
    let cancelled = false;
    const fetchLoyalty = async () => {
      try {
        const res = await getMyLoyaltyApi();
        if (!cancelled && res.success && res.data) {
          setLoyaltyPoints(res.data.loyaltyPoints ?? 0);
        }
      } catch {
        if (!cancelled) {
          setLoyaltyPoints(null);
        }
      }
    };
    void fetchLoyalty();
    return () => {
      cancelled = true;
    };
  }, [isAuthenticated]);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 bg-gradient-to-br from-[#1a1a1a] via-[#2a2a2a] to-[#1a1a1a] ${
        showNavbar ? "translate-y-0" : "-translate-y-full"
      } ${isScrolled || !isHomePage || isAuthSection ? "shadow-lg" : ""}`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Left Section - Logo */}
          <div className="flex items-center flex-shrink-0">
            <Link href="/" className="flex items-center gap-2">
              <div className="bg-[#8B0000] px-4 py-3 flex items-center gap-2 h-full rounded-sm">
                <Image
                  src="/images/logo.png"
                  alt="CineGhar Logo"
                  width={24}
                  height={24}
                  className="object-contain"
                />
                <span className="text-white font-sans text-lg font-semibold">
                  CineGhar
                </span>
              </div>
            </Link>
          </div>

          {/* Middle Section - Navigation Links */}
          <div className="hidden md:flex items-center gap-8 flex-1 justify-center">
            {navLinks.map((link) => {
              const isActive =
                isAuthSection
                  ? pathname === link.href
                  : isHomePage &&
                    !!link.section &&
                    activeSection === link.section &&
                    (link.href === "/" || link.href.startsWith("/#"));

              return (
                <Link
                  key={link.href}
                  href={link.href}
                  onClick={(e) => handleNavClick(e, link.href)}
                  className={`font-sans text-sm transition-colors ${
                    isActive
                      ? "text-white border-b-2 border-white pb-1"
                      : "text-white opacity-90 hover:opacity-100"
                  }`}
                >
                  {link.label}
                </Link>
              );
            })}
          </div>

          {/* Right Section - Search Bar and User/Auth */}
          <div className="flex items-center gap-4 flex-shrink-0">
            {/* Search Bar */}
            <div className="relative hidden lg:block">
              <input
                type="text"
                placeholder="Search movies"
                className={`rounded-lg px-4 py-2 pr-10 text-sm placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#8B0000] w-48 transition-colors ${
                  isScrolled || !isHomePage || isAuthSection
                    ? "bg-gray-800 text-white border border-gray-700"
                    : "bg-white/10 backdrop-blur-sm text-white border border-white/20 placeholder-white/60"
                }`}
              />
              <div className="absolute right-3 top-1/2 transform -translate-y-1/2 pointer-events-none">
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 16 16"
                  fill="none"
                  xmlns="http://www.w3.org/2000/svg"
                >
                  <path
                    d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10zM13 13l-3-3"
                    stroke={isScrolled || !isHomePage || isAuthSection ? "#999" : "rgba(255,255,255,0.6)"}
                    strokeWidth="2"
                    strokeLinecap="round"
                  />
                </svg>
              </div>
            </div>

            {/* Loyalty points + User Avatar or Login/Signup Buttons */}
            {isAuthenticated ? (
              <div className="flex items-center gap-3">
                {loyaltyPoints !== null && (
                  <Link
                    href="/auth/loyalty-points"
                    className="hidden sm:inline-flex items-center gap-1.5 rounded-full bg-black/40 border border-yellow-400/50 px-3 py-1.5 text-[11px] font-medium text-yellow-100 hover:bg-black/60"
                  >
                    <span className="inline-block h-4 w-4 rounded-full bg-yellow-300" />
                    <span>{loyaltyPoints.toLocaleString()} pts</span>
                  </Link>
                )}
                <Link href="/user/profile" className="flex items-center gap-2 group">
                  <div className="w-10 h-10 rounded-full bg-gray-400 overflow-hidden cursor-pointer flex items-center justify-center group-hover:ring-2 group-hover:ring-[#8B0000] transition">
                    {user?.imageUrl ? (
                      // Show uploaded profile image
                      <img
                        src={getImageUrl(user.imageUrl)}
                        alt={user?.name || user?.email || "Profile"}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      // Fallback to initials
                      <span className="text-white font-semibold text-sm">
                        {user?.name?.charAt(0).toUpperCase() ||
                          user?.email?.charAt(0).toUpperCase() ||
                          "U"}
                      </span>
                    )}
                  </div>
                  <span
                    className={`text-sm hidden md:block ${
                      isScrolled || !isHomePage || isAuthSection ? "text-white" : "text-white/90"
                    }`}
                  >
                    {user?.name || user?.email}
                  </span>
                </Link>
                <button
                  onClick={logout}
                  className="px-4 py-2 bg-[#8B0000] text-white font-sans text-sm rounded-lg hover:bg-[#6B0000] transition-colors"
                >
                  Logout
                </button>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  href="/login"
                  className="px-4 py-2 font-sans text-sm transition-colors text-white hover:text-gray-300"
                >
                  Login
                </Link>
                <Link
                  href="/register"
                  className="px-4 py-2 bg-[#8B0000] text-white font-sans text-sm rounded-lg hover:bg-[#6B0000] transition-colors"
                >
                  Signup
                </Link>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
